DispersiveMedia.example:
DispersiveMedia {
  Material = {"Silver"}
  Model = SingleDipoleDrude
  ModelParameters = ComputeFromComplexRefractiveIndex
  InterfaceAveraging = yes
}

Boundary.example:
Boundary {
  Type  = PeriodicOblique
  Sides = {X}
}

Boundary {
  Type  = CPML
  Sides = {Y}
}

CodeVExcitation.example:
CodeVExcitation {
  InputDataFile = {"data_z1.dat", "data_z2.dat"}
  AnchorPoint1  = {-0.5, -0.5, -0.3125}
  AnchorPoint2  = {-0.5, -0.5, -0.25}
  Wavelength    = 550
  Nrise         = 5
}

GaussianBeamExcitation.example:
GaussianBeamExcitation {
  Direction   = fromTop
  Wavelength  = 550
  BeamRadius  = 2.0
  BeamCenter  = {0.0, 0.0, 5.0}
  Intensity   = 0.1 * W/cm2
  Nrise       = 4
}

TruncatedPlaneWaveExcitation.example:
TruncatedPlaneWaveExcitation {
  BoxCorner1 = {0.0, -0.5, 0.0}
  BoxCorner2 = {0.1, -0.5, 0.0}
  Theta      = 0
  Psi        = 0
  Wavelength = 550
  Intensity  = 0.1 * W/cm2
  Nrise      = 4
}

Plot.example:
Plot {
  Name      = "n@node@_Eabs"
  Quantity  = {AbsElectricField, Region}
  TickStep  = 300
  StartTick = 100
  EndTick   = 800
  FinalPlot = yes
}

Sensor.example:
Sensor {
  Name       = "total"
  Quantity   = PhotonFluxDensity
  PlaneY     = -0.2
  Mode       = {Integrate}
}

RTA.example:
RTA {
  Log = {R, T, A, RTA}
  StartTick = 0
  LogPrecision = 4
}

Farfield.example:
Farfield {
  Name        = "n@node@_ff"
  Region      = "nearfield_plane"
  Radius      = 500
  PolarRange  = {0, 90, 1}
  AzimuthalRange = {0, 360, 1}
}

Monitor.example:
Monitor {
  Name     = "point1"
  Location = {0.0, 0.0, 0.0}
  Quantity = {AbsElectricField, AbsMagneticField}
  StartTick = 100
}
